    getWorkflowGuideSectionDefinition(cardId, flow = null) {
        const state = flow || this.getInputSectionFlowState();
        return ControllerGuidance.getWorkflowGuideSectionDefinition(cardId, state.nextSectionId);
    },

    setWorkflowGuideFocus(targetId = null, type = 'field') {
        this.workflowGuideFocusId = targetId || null;
        this.workflowGuideFocusType = targetId ? type : 'section';
        this.renderWorkflowGuide();
    },

    getWorkflowGuideFocusDefinition(flow = null) {
        const state = flow || this.getInputSectionFlowState();
        return ControllerGuidance.resolveWorkflowGuideFocus({
            focusId: this.workflowGuideFocusId,
            focusType: this.workflowGuideFocusType,
            fieldDefinition: this.workflowGuideFocusType === 'field'
                ? this.getWorkflowGuideFieldDefinitions()[this.workflowGuideFocusId]
                : null,
            sectionDefinition: this.workflowGuideFocusType === 'section'
                ? this.getWorkflowGuideSectionDefinition(this.workflowGuideFocusId, state)
                : null,
            fallbackSectionDefinition: this.getWorkflowGuideSectionDefinition(state.nextSectionId, state)
        });
    },

    getDefaultInputSectionExpanded(cardId, flow = null) {
        const state = flow || this.getInputSectionFlowState();
        return ControllerGuidance.shouldInputSectionBeExpanded(cardId, state);
    },

    initializeInputSectionFlow() {
        const stored = this.loadInputSectionState();

        this.getInputSectionDefinitions().forEach(def => {
            const card = document.getElementById(def.id);
            if (!card || card.dataset.inputSectionReady === 'true') return;

            card.classList.add('input-section-card');
            card.dataset.inputSectionReady = 'true';
            card.dataset.sectionLabel = def.label;
            card.dataset.sectionStep = def.stepLabel;

            const header = this.getInputSectionHeader(card);
            if (!header) return;

            if (header.classList?.contains('section-header-inline')) {
                header.classList.add('input-section-inline-header');
            } else {
                header.classList?.add('input-section-title');
            }

            const summary = document.createElement('div');
            summary.id = `${def.id}Summary`;
            summary.className = 'input-section-summary';
            this.insertInputSectionSummary(card, header, summary);

            const toggle = document.createElement('button');
            toggle.type = 'button';
            toggle.className = 'input-section-toggle';
            toggle.textContent = 'Collapse';
            toggle.setAttribute('aria-expanded', 'true');
            toggle.setAttribute('aria-controls', def.id);
            toggle.setAttribute('aria-label', `${def.label}: collapse section`);
            toggle.onclick = () => this.toggleInputSection(def.id);

            if (header.classList?.contains('section-header-inline')) {
                header.appendChild(toggle);
            } else {
                toggle.classList.add('input-section-toggle-floating');
                card.appendChild(toggle);
            }

            const hasStoredValue = Object.prototype.hasOwnProperty.call(stored, def.id);
            const expanded = hasStoredValue ? !!stored[def.id] : this.getDefaultInputSectionExpanded(def.id);
            this.setInputSectionExpanded(def.id, expanded, { persist: false });
        });

        this._inputSectionFlowInitialized = true;
        this.refreshInputSectionFlow({ preserveState: true });
    },

    setInputSectionExpanded(cardId, expanded, options = {}) {
        const card = document.getElementById(cardId);
        if (!card) return;

        const isExpanded = !!expanded;
        card.dataset.sectionExpanded = isExpanded ? 'true' : 'false';
        card.classList.toggle('input-section-collapsed', !isExpanded);

        const toggle = this.getInputSectionToggleElement(card);
        if (toggle) {
            toggle.textContent = isExpanded ? 'Collapse' : 'Expand';
            toggle.setAttribute('aria-expanded', isExpanded ? 'true' : 'false');
            toggle.setAttribute('aria-label', `${card.dataset.sectionLabel || 'Section'}: ${isExpanded ? 'collapse' : 'expand'} section`);
        }

        this.getInputSectionContentNodes(card).forEach(node => {
            node.classList.toggle('input-section-hidden', !isExpanded);
        });

        if (options.persist !== false) {
            const state = this.loadInputSectionState();
            state[cardId] = isExpanded;
            this.saveInputSectionState(state);
        }
    },

    toggleInputSection(cardId) {
        const card = document.getElementById(cardId);
        if (!card) return;
        const current = card.dataset.sectionExpanded !== 'false';
        this.setInputSectionExpanded(cardId, !current);
    },

    focusInputSection(cardId) {
        const card = document.getElementById(cardId);
        if (!card) return;
        this.setInputSectionExpanded(cardId, true);
        this.setWorkflowGuideFocus(cardId, 'section');
        if (typeof card.scrollIntoView === 'function') {
            card.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
        const firstControl = Array.from(card.querySelectorAll?.('input, select, textarea, button') || [])
            .find(node => !node.classList?.contains('input-section-toggle'));
        if (firstControl && typeof firstControl.focus === 'function') {
            this.setWorkflowGuideFocus(firstControl.id || cardId, firstControl.id ? 'field' : 'section');
            firstControl.focus();
        }
    },

    refreshInputSectionFlow(options = {}) {
        if (!this._inputSectionFlowInitialized) return;

        const flow = this.getInputSectionFlowState();
        const stored = this.loadInputSectionState();

        this.getInputSectionDefinitions().forEach(def => {
            const card = document.getElementById(def.id);
            if (!card) return;

            const summary = this.getInputSectionSummaryElement(def.id);
            if (summary) {
                summary.textContent = this.getInputSectionSummary(def.id, flow);
            }

            const isVisible = !card.classList?.contains('hidden');
            card.classList.toggle('input-section-recommended', isVisible && def.id === flow.nextSectionId);

            const hasStoredValue = Object.prototype.hasOwnProperty.call(stored, def.id);
            const hasRuntimeState = typeof card.dataset.sectionExpanded !== 'undefined';
            if (!hasRuntimeState || (!options.preserveState && !hasStoredValue)) {
                this.setInputSectionExpanded(def.id, this.getDefaultInputSectionExpanded(def.id, flow), { persist: false });
            }
        });

        this.renderWorkflowGuide(flow);
    },

