    getBusinessContextSummary(config) {
        const resolvedConfig = config || this.getConfig();
        const profileKey = resolvedConfig?.businessProfile || 'custom_mixed_site';
        const operatingIntentKey = resolvedConfig?.operatingIntent || 'backup_only';
        const continuityKey = resolvedConfig?.continuityClass || 'business_critical';
        const operatingScheduleKey = resolvedConfig?.operatingSchedulePreset || 'business_day';
        const profile = resolvedConfig?.businessProfileDefinition || this.getBusinessProfileDefinition(profileKey);
        const operatingIntent = resolvedConfig?.operatingIntentDefinition || this.getBusinessOperatingIntentDefinition(operatingIntentKey);
        const continuityClass = resolvedConfig?.continuityClassDefinition || this.getBusinessContinuityClassDefinition(continuityKey);
        const operatingSchedule = resolvedConfig?.operatingScheduleDefinition || this.getOperatingScheduleDefinition(operatingScheduleKey);
        return ControllerPayloads.summarizeBusinessContext({
            config: resolvedConfig,
            profile,
            operatingIntent,
            continuityClass,
            operatingSchedule
        });
    },

