            ...(formalStudyIntake.items.length ? [`Intake gates: ${formalStudyIntake.status === 'fail' ? 'Open gates remain' : formalStudyIntake.status === 'warn' ? 'Review gates remain' : 'Ready for kickoff'}`] : []),
            ...(formalStudyScreening.items.length ? [`Screening snapshot: ${formalStudyScreening.status === 'fail' ? 'Open screening rows remain' : formalStudyScreening.status === 'warn' ? 'Review screening rows remain' : 'Key screening rows pinned'}`] : []),
            ...(utilityInputs.applicationReference ? [`Reference: ${utilityInputs.applicationReference}`] : []),
