    escapeDelimitedCell(value, delimiter = ',') {
        const normalized = value == null
            ? ''
            : Array.isArray(value)
                ? value.join(' | ')
                : String(value).replace(/\r\n/g, '\n').replace(/\r/g, '\n');
        const escaped = normalized.replace(/"/g, '""');
        return escaped.includes(delimiter) || escaped.includes('"') || escaped.includes('\n')
            ? `"${escaped}"`
            : escaped;
    },

    buildDelimitedText(rows, delimiter = ',') {
        return (rows || [])
            .map(row => (row || []).map(cell => this.escapeDelimitedCell(cell, delimiter)).join(delimiter))
            .join('\n');
    },

